package claseString;
/*Dada una cadena "JavaProgramming", 
 * extrae y muestra "Programming" usando substring().*/
public class Ejercicio10 {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		String cadena = "JavaProgramming";
		String resultado = cadena.substring(4);
		System.out.println(resultado);
	}

}
